require("dotenv").config();const DiscordNotifier=require("./services/discordNotifier"),NFTTracker=require("./services/nftTracker");async function sleep(ms){return new Promise((r=>setTimeout(r,ms)))}async function testBidAccepted(notifier,tracker){const data={type:"sale",isBulk:!1,walletName:"TestWallet",walletAddress:"0x1234567890123456789012345678901234567890",tokenName:"Test Collection",tokenId:"1234",contractAddress:"0x1234567890123456789012345678901234567890",transactionHash:"0x"+"bid".repeat(21),chainName:"Ethereum",timestamp:new Date,price:.5,priceUSD:1e3,quantity:1,imageUrl:null,nftName:"Test Collection #1234",nativeSymbol:"WETH",floorPrice:.4,isBidAccepted:!0,buyPrice:.3,buyPriceUSD:600,buyTimestamp:new Date(Date.now()-864e5)};await notifier.sendNotification(data,tracker)}async function testBidPurchase(notifier,tracker){const data={type:"purchase",isBulk:!1,walletName:"TestWallet",walletAddress:"0x1234567890123456789012345678901234567890",tokenName:"Test Collection",tokenId:"5678",contractAddress:"0x1234567890123456789012345678901234567890",transactionHash:"0x"+"buy".repeat(21),chainName:"Ethereum",timestamp:new Date,price:.6,priceUSD:1200,quantity:1,imageUrl:null,nftName:"Test Collection #5678",nativeSymbol:"WETH",floorPrice:.4,isBidAccepted:!1};await notifier.sendNotification(data,tracker)}async function run(){const notifier=new DiscordNotifier,tracker=new NFTTracker;try{console.log("🔗 Connecting to Discord..."),await notifier.connect(),await new Promise((resolve=>{const start=Date.now(),timer=setInterval((()=>{(notifier.isReady||Date.now()-start>1e4)&&(clearInterval(timer),resolve())}),100)})),console.log("🧪 Testing bid accepted scenario (WETH offer accepted)"),await testBidAccepted(notifier,tracker),await sleep(1e3),console.log("🧪 Testing bid purchase scenario (buying via bid)"),await testBidPurchase(notifier,tracker),console.log("✅ All bid scenarios tested")}catch(e){console.error("❌ Bid scenarios failed:",e)}finally{await notifier.disconnect()}}run();